export const FAMILY_WAY_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Family Way</title>\n<style>\n  /* JFT site styling — brand-green (#2d8163) on sand cream, Inter\n     font, white cards with light borders and subtle shadows. Matches\n     the rest of the site so the quiz feels native rather than like\n     a third-party tool dropped in. */\n\n  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }\n\n  :root {\n    --ink:        #111827;\n    --ink-soft:   #4b5e5a;\n    --paper:      #fafaf7;   /* sand-50 */\n    --sand-100:   #f5f4f0;\n    --sand-200:   #ebe9e1;\n    --brand-50:   #f4faf7;\n    --brand-100:  #e3f1ea;\n    --brand-200:  #c9e3d2;\n    --brand-500:  #4ea27a;\n    --brand-600:  #2d8163;   /* primary */\n    --brand-700:  #235d4a;\n    --brand-900:  #173b30;\n    --brand-950:  #112b23;\n    --muted:      #6b7280;\n    --border:     #e5e7eb;   /* gray-200 */\n    --border-soft:#f3f4f6;   /* gray-100 */\n    --card:       #ffffff;\n    --amber-700:  #b45309;\n    --rose-700:   #be123c;\n    color-scheme: light;\n  }\n\n  html, body {\n    color-scheme: light;\n    background: var(--paper);\n    color: var(--ink);\n  }\n  body {\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Inter', Roboto, 'Helvetica Neue', Arial, sans-serif;\n    line-height: 1.65;\n    min-height: 100vh;\n    -webkit-font-smoothing: antialiased;\n  }\n\n  .screen { display: none; }\n  .screen.active { display: block; }\n\n  .shell {\n    max-width: 680px;\n    margin: 0 auto;\n    padding: 24px 20px 60px;\n  }\n\n  /* ── LANDING ── */\n  .landing { text-align: center; padding: 70px 24px 50px; max-width: 600px; margin: 0 auto; }\n  .landing .eyebrow {\n    display: inline-block;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--brand-600);\n    margin-bottom: 22px;\n  }\n  .landing h1 {\n    font-size: clamp(28px, 5.5vw, 38px);\n    font-weight: 700;\n    line-height: 1.15;\n    letter-spacing: -0.015em;\n    margin-bottom: 18px;\n    color: var(--ink);\n  }\n  .landing .lede {\n    font-size: 16px;\n    color: var(--muted);\n    max-width: 480px;\n    margin: 0 auto 32px;\n    line-height: 1.6;\n  }\n  .start-btn {\n    background: var(--brand-600);\n    color: white;\n    border: none;\n    font-family: inherit;\n    font-size: 15px;\n    font-weight: 600;\n    padding: 14px 28px;\n    border-radius: 8px;\n    cursor: pointer;\n    transition: background 0.15s ease;\n  }\n  .start-btn:hover { background: var(--brand-700); }\n  .landing .time {\n    display: block;\n    margin-top: 14px;\n    font-size: 13px;\n    color: var(--muted);\n  }\n\n  /* ── PROGRESS ── */\n  .progress-wrap {\n    position: sticky;\n    top: 0;\n    background: var(--paper);\n    padding: 18px 20px 14px;\n    z-index: 5;\n    max-width: 680px;\n    margin: 0 auto;\n  }\n  .progress-label {\n    font-size: 11px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 10px;\n    font-weight: 700;\n  }\n  .progress {\n    height: 4px;\n    background: var(--border);\n    border-radius: 2px;\n    overflow: hidden;\n  }\n  .progress-fill {\n    height: 100%;\n    background: var(--brand-600);\n    border-radius: 2px;\n    transition: width 0.4s cubic-bezier(.4,0,.2,1);\n  }\n\n  /* ── SECTIONS ── */\n  .q-section { display: none; padding: 8px 0 0; }\n  .q-section.active { display: block; }\n  .q-section h2 {\n    font-size: 24px;\n    font-weight: 700;\n    letter-spacing: -0.01em;\n    margin-bottom: 6px;\n    line-height: 1.25;\n    color: var(--ink);\n  }\n  .section-desc {\n    font-size: 14px;\n    color: var(--muted);\n    margin-bottom: 28px;\n    line-height: 1.55;\n  }\n\n  /* ── FIELDS ── */\n  .q-field { margin-bottom: 26px; }\n  .q-field > label {\n    display: block;\n    font-size: 14px;\n    font-weight: 600;\n    margin-bottom: 10px;\n    color: var(--ink);\n    line-height: 1.45;\n  }\n\n  .btn-group { display: grid; gap: 8px; }\n\n  .btn-option {\n    background: var(--card);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    padding: 13px 16px;\n    text-align: left;\n    font-size: 14px;\n    font-weight: 500;\n    color: var(--ink);\n    cursor: pointer;\n    transition: border-color 0.15s ease, background 0.15s ease, color 0.15s ease, box-shadow 0.15s ease;\n    width: 100%;\n    font-family: inherit;\n    line-height: 1.45;\n  }\n  .btn-option:hover {\n    border-color: var(--brand-200);\n    background: var(--brand-50);\n  }\n  .btn-option.selected {\n    border-color: var(--brand-600);\n    background: var(--brand-50);\n    color: var(--brand-700);\n    font-weight: 600;\n    box-shadow: 0 0 0 1px var(--brand-600) inset;\n  }\n\n  /* Age grid (single child) */\n  .age-grid {\n    display: grid;\n    grid-template-columns: repeat(6, 1fr);\n    gap: 6px;\n  }\n  .age-grid .btn-option {\n    text-align: center;\n    padding: 12px 4px;\n    font-size: 14px;\n    font-weight: 600;\n  }\n\n  /* Slider */\n  .slider-wrap {\n    background: var(--card);\n    border: 1px solid var(--border);\n    border-radius: 16px;\n    padding: 22px 20px;\n  }\n  .slider-readout {\n    font-size: 36px;\n    font-weight: 700;\n    color: var(--brand-600);\n    text-align: center;\n    margin-bottom: 12px;\n    letter-spacing: -0.02em;\n    line-height: 1;\n  }\n  .slider-readout sub {\n    font-size: 16px;\n    color: var(--muted);\n    font-weight: 500;\n    vertical-align: baseline;\n    margin-left: 2px;\n  }\n  input[type=\"range\"] {\n    -webkit-appearance: none;\n    appearance: none;\n    width: 100%;\n    height: 4px;\n    background: var(--border);\n    border-radius: 2px;\n    outline: none;\n    margin: 12px 0;\n  }\n  input[type=\"range\"]::-webkit-slider-thumb {\n    -webkit-appearance: none;\n    appearance: none;\n    width: 22px;\n    height: 22px;\n    border-radius: 50%;\n    background: var(--brand-600);\n    cursor: pointer;\n    box-shadow: 0 2px 6px rgba(45,129,99,0.35);\n  }\n  input[type=\"range\"]::-moz-range-thumb {\n    width: 22px;\n    height: 22px;\n    border-radius: 50%;\n    background: var(--brand-600);\n    cursor: pointer;\n    border: none;\n    box-shadow: 0 2px 6px rgba(45,129,99,0.35);\n  }\n  .slider-labels {\n    display: flex;\n    justify-content: space-between;\n    font-size: 12px;\n    color: var(--muted);\n    margin-top: 6px;\n  }\n\n  /* Textarea */\n  textarea {\n    width: 100%;\n    background: var(--card);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    padding: 14px;\n    font-family: inherit;\n    font-size: 14px;\n    color: var(--ink);\n    resize: vertical;\n    min-height: 90px;\n    outline: none;\n    line-height: 1.55;\n  }\n  textarea:focus { border-color: var(--brand-600); box-shadow: 0 0 0 1px var(--brand-600); }\n\n  /* ── NAV ── */\n  .q-nav {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    margin-top: 36px;\n    gap: 14px;\n  }\n  .btn-back, .btn-next {\n    font-family: inherit;\n    font-size: 14px;\n    font-weight: 500;\n    border-radius: 8px;\n    cursor: pointer;\n    border: none;\n    transition: background 0.15s ease, color 0.15s ease;\n  }\n  .btn-back {\n    background: transparent;\n    color: var(--muted);\n    padding: 12px 18px;\n  }\n  .btn-back:hover { color: var(--ink); }\n  .btn-next {\n    background: var(--brand-600);\n    color: white;\n    font-weight: 600;\n    padding: 13px 24px;\n  }\n  .btn-next:hover { background: var(--brand-700); }\n\n  /* ── RESULTS ── */\n  .result-card {\n    background: var(--card);\n    border: 1px solid var(--border-soft);\n    border-radius: 16px;\n    padding: 28px;\n    margin-bottom: 14px;\n    box-shadow: 0 1px 2px rgba(0,0,0,0.04);\n  }\n\n  .score-hero { text-align: center; padding: 40px 28px 36px; }\n  .score-band {\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.16em;\n    text-transform: uppercase;\n    margin-bottom: 14px;\n  }\n  .score-number {\n    font-size: 76px;\n    font-weight: 700;\n    letter-spacing: -0.03em;\n    line-height: 1;\n  }\n  .score-out-of {\n    font-size: 22px;\n    color: var(--muted);\n    font-weight: 500;\n    margin-left: 2px;\n  }\n  .score-tagline {\n    font-size: 18px;\n    font-weight: 500;\n    color: var(--ink);\n    margin-top: 16px;\n    line-height: 1.4;\n    max-width: 360px;\n    margin-left: auto;\n    margin-right: auto;\n  }\n  .score-band.high   { color: var(--brand-600); }\n  .score-band.medium { color: var(--amber-700); }\n  .score-band.low    { color: var(--rose-700); }\n  .score-number.high   { color: var(--brand-600); }\n  .score-number.medium { color: var(--amber-700); }\n  .score-number.low    { color: var(--rose-700); }\n\n  /* Family profile (sand background) */\n  .profile-card {\n    background: var(--sand-100);\n    border: 1px solid var(--border-soft);\n    border-radius: 16px;\n    padding: 26px;\n    margin-bottom: 14px;\n  }\n  .profile-card h3 {\n    font-size: 18px;\n    font-weight: 700;\n    margin-bottom: 16px;\n    color: var(--ink);\n  }\n  .profile-row {\n    padding: 12px 0;\n    border-bottom: 1px dashed rgba(0,0,0,0.08);\n  }\n  .profile-row:first-of-type { padding-top: 0; }\n  .profile-row:last-child { border-bottom: none; padding-bottom: 0; }\n  .profile-label {\n    font-size: 10px;\n    font-weight: 700;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--brand-600);\n    margin-bottom: 5px;\n  }\n  .profile-value {\n    font-size: 14.5px;\n    line-height: 1.55;\n    color: var(--ink);\n  }\n  .tag {\n    display: inline-block;\n    background: var(--card);\n    border: 1px solid var(--border);\n    border-radius: 6px;\n    padding: 3px 8px;\n    font-size: 12px;\n    margin-right: 4px;\n    margin-top: 4px;\n    color: var(--ink);\n  }\n\n  /* Strengths / Challenges grid */\n  .swot-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 12px;\n    margin-bottom: 14px;\n  }\n  @media (max-width: 600px) {\n    .swot-grid { grid-template-columns: 1fr; }\n  }\n  .swot-card {\n    background: var(--card);\n    border: 1px solid var(--border-soft);\n    border-radius: 16px;\n    padding: 22px;\n    box-shadow: 0 1px 2px rgba(0,0,0,0.04);\n  }\n  .swot-card h4 {\n    font-size: 14px;\n    font-weight: 700;\n    margin-bottom: 14px;\n    color: var(--ink);\n  }\n  .swot-card ul { list-style: none; }\n  .swot-card li {\n    font-size: 13.5px;\n    line-height: 1.55;\n    padding-left: 22px;\n    position: relative;\n    margin-bottom: 12px;\n    color: var(--ink);\n  }\n  .swot-card li:last-child { margin-bottom: 0; }\n  .swot-card.strengths li::before {\n    content: '✓';\n    position: absolute;\n    left: 0;\n    top: 0;\n    color: var(--brand-600);\n    font-weight: 700;\n  }\n  .swot-card.challenges li::before {\n    content: '!';\n    position: absolute;\n    left: 5px;\n    top: 0;\n    color: var(--amber-700);\n    font-weight: 700;\n  }\n\n  /* Actions */\n  .actions-card {\n    background: var(--card);\n    border: 1px solid var(--border-soft);\n    border-radius: 16px;\n    padding: 26px;\n    margin-bottom: 14px;\n    box-shadow: 0 1px 2px rgba(0,0,0,0.04);\n  }\n  .actions-card h3 {\n    font-size: 16px;\n    font-weight: 700;\n    margin-bottom: 16px;\n    color: var(--ink);\n  }\n  .actions-card ul { list-style: none; }\n  .actions-card li {\n    padding-left: 24px;\n    position: relative;\n    margin-bottom: 14px;\n    font-size: 14px;\n    line-height: 1.6;\n  }\n  .actions-card li:last-child { margin-bottom: 0; }\n  .actions-card li::before {\n    content: '→';\n    position: absolute;\n    left: 0;\n    top: 1px;\n    color: var(--brand-600);\n    font-weight: 700;\n  }\n\n  /* Next step (brand tint) */\n  .next-step {\n    background: var(--brand-50);\n    border: 1px solid var(--brand-200);\n    border-radius: 16px;\n    padding: 26px;\n    margin-bottom: 14px;\n  }\n  .next-step h3 {\n    font-size: 18px;\n    font-weight: 700;\n    margin-bottom: 12px;\n    color: var(--brand-900);\n  }\n  .next-step p {\n    font-size: 14.5px;\n    line-height: 1.65;\n    color: var(--ink);\n  }\n\n  /* CTA (dark brand) */\n  .cta-card {\n    background: var(--brand-950);\n    color: var(--paper);\n    border-radius: 16px;\n    padding: 28px;\n    margin-bottom: 24px;\n  }\n  .cta-card .eyebrow {\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.16em;\n    text-transform: uppercase;\n    color: var(--brand-200);\n    margin-bottom: 12px;\n  }\n  .cta-card h3 {\n    font-size: 22px;\n    font-weight: 700;\n    margin-bottom: 14px;\n    color: white;\n  }\n  .cta-card p {\n    font-size: 14px;\n    line-height: 1.65;\n    color: rgba(255,255,255,0.8);\n    margin-bottom: 20px;\n  }\n  .cta-btn {\n    display: inline-block;\n    background: var(--brand-600);\n    color: white;\n    text-decoration: none;\n    font-weight: 600;\n    font-size: 14px;\n    padding: 12px 22px;\n    border-radius: 8px;\n    font-family: inherit;\n    transition: background 0.15s ease;\n  }\n  .cta-btn:hover { background: var(--brand-700); }\n\n  .restart-link {\n    display: block;\n    text-align: center;\n    margin: 20px auto;\n    background: none;\n    border: none;\n    color: var(--muted);\n    font-size: 13px;\n    cursor: pointer;\n    font-family: inherit;\n    text-decoration: underline;\n  }\n  .restart-link:hover { color: var(--ink); }\n</style>\n</head>\n<body>\n\n<!-- ═══ LANDING ═══ -->\n<div id=\"landing\" class=\"screen landing active\">\n  <span class=\"eyebrow\">Family Way</span>\n  <h1>Could long-term travel actually work for your family?</h1>\n  <p class=\"lede\">An honest readiness check, built for families dreaming about taking the leap. Personal results in 5 minutes.</p>\n  <button class=\"start-btn\" onclick=\"startQuiz()\">Start the quiz →</button>\n  <span class=\"time\">~5 minutes · No sign-up · Free</span>\n</div>\n\n<!-- ═══ QUIZ ═══ -->\n<div id=\"quiz\" class=\"screen\">\n  <div class=\"progress-wrap\">\n    <div class=\"progress-label\" id=\"progressLabel\">Section 1 of 7</div>\n    <div class=\"progress\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:14%\"></div></div>\n  </div>\n  <div class=\"shell\">\n\n    <!-- SECTION 1: FAMILY -->\n    <div class=\"q-section active\" id=\"section-1\">\n      <h2>Your Family</h2>\n      <p class=\"section-desc\">Tell us who's travelling.</p>\n\n      <div class=\"q-field\">\n        <label>How many adults are travelling?</label>\n        <div class=\"btn-group\" data-field=\"adults\">\n          <button class=\"btn-option\" data-value=\"1\">1 — Solo parent</button>\n          <button class=\"btn-option\" data-value=\"2\">2 — Couple or partners</button>\n          <button class=\"btn-option\" data-value=\"3+\">3 or more — Extended family</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Are you travelling with children?</label>\n        <div class=\"btn-group\" data-field=\"hasChildren\">\n          <button class=\"btn-option\" data-value=\"yes\">Yes</button>\n          <button class=\"btn-option\" data-value=\"no\">No</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"numChildrenField\" style=\"display:none\">\n        <label>How many children?</label>\n        <div class=\"btn-group\" data-field=\"numChildren\">\n          <button class=\"btn-option\" data-value=\"1\">1</button>\n          <button class=\"btn-option\" data-value=\"2\">2</button>\n          <button class=\"btn-option\" data-value=\"3\">3</button>\n          <button class=\"btn-option\" data-value=\"4+\">4 or more</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"childAgeExactField\" style=\"display:none\">\n        <label>How old are they?</label>\n        <div class=\"age-grid btn-group\" data-field=\"childExactAge\">\n          <button class=\"btn-option\" data-value=\"0\">&lt;1</button>\n          <button class=\"btn-option\" data-value=\"1\">1</button>\n          <button class=\"btn-option\" data-value=\"2\">2</button>\n          <button class=\"btn-option\" data-value=\"3\">3</button>\n          <button class=\"btn-option\" data-value=\"4\">4</button>\n          <button class=\"btn-option\" data-value=\"5\">5</button>\n          <button class=\"btn-option\" data-value=\"6\">6</button>\n          <button class=\"btn-option\" data-value=\"7\">7</button>\n          <button class=\"btn-option\" data-value=\"8\">8</button>\n          <button class=\"btn-option\" data-value=\"9\">9</button>\n          <button class=\"btn-option\" data-value=\"10\">10</button>\n          <button class=\"btn-option\" data-value=\"11\">11</button>\n          <button class=\"btn-option\" data-value=\"12\">12</button>\n          <button class=\"btn-option\" data-value=\"13\">13</button>\n          <button class=\"btn-option\" data-value=\"14\">14</button>\n          <button class=\"btn-option\" data-value=\"15\">15</button>\n          <button class=\"btn-option\" data-value=\"16\">16</button>\n          <button class=\"btn-option\" data-value=\"17\">17</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"childAgesRangeField\" style=\"display:none\">\n        <label>What's the age range?</label>\n        <div class=\"btn-group\" data-field=\"childAges\">\n          <button class=\"btn-option\" data-value=\"all-young\">All under 5</button>\n          <button class=\"btn-option\" data-value=\"mixed\">Some young, some older</button>\n          <button class=\"btn-option\" data-value=\"all-older\">All 5 and over</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Any long-term travel experience as a family?</label>\n        <div class=\"btn-group\" data-field=\"experience\">\n          <button class=\"btn-option\" data-value=\"yes\">Yes, we've done this before</button>\n          <button class=\"btn-option\" data-value=\"some\">Some — short trips abroad</button>\n          <button class=\"btn-option\" data-value=\"no\">None — this would be new</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 2: INTENTION -->\n    <div class=\"q-section\" id=\"section-2\">\n      <h2>Your Intention</h2>\n      <p class=\"section-desc\">What are you actually hoping to do?</p>\n\n      <div class=\"q-field\">\n        <label>How long do you want to travel for?</label>\n        <div class=\"btn-group\" data-field=\"duration\">\n          <button class=\"btn-option\" data-value=\"1-3m\">1–3 months</button>\n          <button class=\"btn-option\" data-value=\"3-6m\">3–6 months</button>\n          <button class=\"btn-option\" data-value=\"6-12m\">6–12 months</button>\n          <button class=\"btn-option\" data-value=\"12m+\">12 months or more</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>What's driving this dream?</label>\n        <div class=\"btn-group\" data-field=\"goal\">\n          <button class=\"btn-option\" data-value=\"adventure\">Adventure — see the world</button>\n          <button class=\"btn-option\" data-value=\"education\">Education — broaden the kids' horizons</button>\n          <button class=\"btn-option\" data-value=\"lifestyle\">Lifestyle — escape the daily grind</button>\n          <button class=\"btn-option\" data-value=\"test\">Test — see if this life is for us</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>When are you realistically hoping to leave?</label>\n        <div class=\"btn-group\" data-field=\"timeline\">\n          <button class=\"btn-option\" data-value=\"asap\">As soon as possible (within 6 months)</button>\n          <button class=\"btn-option\" data-value=\"1year\">In 6–12 months</button>\n          <button class=\"btn-option\" data-value=\"2year\">In 1–2 years</button>\n          <button class=\"btn-option\" data-value=\"flexible\">No fixed timeline — when it's right</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 3: WORK & INCOME -->\n    <div class=\"q-section\" id=\"section-3\">\n      <h2>Work &amp; Income</h2>\n      <p class=\"section-desc\">How money will flow on the road.</p>\n\n      <div class=\"q-field\">\n        <label>How do you work right now?</label>\n        <div class=\"btn-group\" data-field=\"workNow\">\n          <button class=\"btn-option\" data-value=\"office\">Office or site based — I need to be physically present</button>\n          <button class=\"btn-option\" data-value=\"home-uk\">I work from home, but I'm tied to my home country</button>\n          <button class=\"btn-option\" data-value=\"anywhere\">I work remotely and could do this job from anywhere in the world</button>\n          <button class=\"btn-option\" data-value=\"self-employed\">Self-employed / freelance / run my own business</button>\n          <button class=\"btn-option\" data-value=\"not-working\">Not currently working</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"workLocationField\" style=\"display:none\">\n        <label>Could your work actually be done from another country?</label>\n        <div class=\"btn-group\" data-field=\"workLocation\">\n          <button class=\"btn-option\" data-value=\"yes\">Yes — fully possible</button>\n          <button class=\"btn-option\" data-value=\"maybe\">Maybe — I'd need to ask</button>\n          <button class=\"btn-option\" data-value=\"no\">No — tied to home</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"workWhenLeaveField\" style=\"display:none\">\n        <label>When you leave to travel — what happens with work?</label>\n        <div class=\"btn-group\" data-field=\"workWhenLeave\">\n          <button class=\"btn-option\" data-value=\"keep-going\">I keep working exactly as I do now — my job travels with me</button>\n          <button class=\"btn-option\" data-value=\"sabbatical\">I'd negotiate a sabbatical or career break and return to my job after</button>\n          <button class=\"btn-option\" data-value=\"reduce\">I could go part-time or reduce hours — earn something while travelling</button>\n          <button class=\"btn-option\" data-value=\"quit\">I'd resign — full clean break, no income from this job</button>\n          <button class=\"btn-option\" data-value=\"new-income\">I'd leave and replace this income with something new (freelance, remote job, content, etc.)</button>\n          <button class=\"btn-option\" data-value=\"unsure\">Not sure yet — I haven't figured this part out</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"newIncomeProgressField\" style=\"display:none\">\n        <label>How far along are you with building that new income?</label>\n        <div class=\"btn-group\" data-field=\"newIncomeProgress\">\n          <button class=\"btn-option\" data-value=\"earning\">Already earning from it</button>\n          <button class=\"btn-option\" data-value=\"started\">Started building but not yet earning</button>\n          <button class=\"btn-option\" data-value=\"idea\">It's an idea I haven't started yet</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Overall — will you have earned income coming in while travelling?</label>\n        <div class=\"btn-group\" data-field=\"travelIncome\">\n          <button class=\"btn-option\" data-value=\"yes-both\">Yes — both adults will be earning</button>\n          <button class=\"btn-option\" data-value=\"yes-one\">Yes — one adult will be earning</button>\n          <button class=\"btn-option\" data-value=\"building\">Building toward it — should be by the time we leave</button>\n          <button class=\"btn-option\" data-value=\"no\">No — we'll be living off savings</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Do you have any residual or passive income?</label>\n        <div class=\"btn-group\" data-field=\"residualIncome\">\n          <button class=\"btn-option\" data-value=\"yes-covers\">Yes — covers our home costs (rental income, etc.)</button>\n          <button class=\"btn-option\" data-value=\"yes-partial\">Yes — partially supplements (smaller rental, royalties, etc.)</button>\n          <button class=\"btn-option\" data-value=\"potential\">Potential — we could rent out our home or similar</button>\n          <button class=\"btn-option\" data-value=\"no\">None</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 4: FINANCES -->\n    <div class=\"q-section\" id=\"section-4\">\n      <h2>Your Finances</h2>\n      <p class=\"section-desc\">Be honest — this shapes what's realistic.</p>\n\n      <div class=\"q-field\">\n        <label>Roughly how much could you save per month right now?</label>\n        <div class=\"btn-group\" data-field=\"savingsRate\">\n          <button class=\"btn-option\" data-value=\"under50\">Under £50</button>\n          <button class=\"btn-option\" data-value=\"50-250\">£50–£250</button>\n          <button class=\"btn-option\" data-value=\"251-500\">£250–£500</button>\n          <button class=\"btn-option\" data-value=\"501-1000\">£500–£1,000</button>\n          <button class=\"btn-option\" data-value=\"1000+\">£1,000+</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>How long could you keep saving at that rate?</label>\n        <div class=\"btn-group\" data-field=\"savingsDuration\">\n          <button class=\"btn-option\" data-value=\"under6m\">Less than 6 months</button>\n          <button class=\"btn-option\" data-value=\"6-12m\">6–12 months</button>\n          <button class=\"btn-option\" data-value=\"1-2yr\">1–2 years</button>\n          <button class=\"btn-option\" data-value=\"2yr+\">2 years or more</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Do you have any savings set aside already?</label>\n        <div class=\"btn-group\" data-field=\"existingSavings\">\n          <button class=\"btn-option\" data-value=\"yes-strong\">Yes — more than £5,000</button>\n          <button class=\"btn-option\" data-value=\"yes-some\">Yes — less than £5,000</button>\n          <button class=\"btn-option\" data-value=\"no\">Nothing set aside yet</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Do you have expenses at home you'd need to keep covering while away?</label>\n        <div class=\"btn-group\" data-field=\"homeExpenses\">\n          <button class=\"btn-option\" data-value=\"yes\">Yes — mortgage, bills, subscriptions, storage, etc.</button>\n          <button class=\"btn-option\" data-value=\"no\">No — we'd let the home go, or it's covered</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Do you think there's room to cut your current outgoings?</label>\n        <div class=\"btn-group\" data-field=\"spendingHabits\">\n          <button class=\"btn-option\" data-value=\"lean\">We're already lean — not much fat to trim</button>\n          <button class=\"btn-option\" data-value=\"some-cuts\">Some — a few subscriptions / habits could go</button>\n          <button class=\"btn-option\" data-value=\"lots-of-cuts\">Plenty — we could cut significantly if we focused</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 5: EDUCATION -->\n    <div class=\"q-section\" id=\"section-5\">\n      <h2>Education &amp; Worldschooling</h2>\n      <p class=\"section-desc\">How school fits in, or doesn't.</p>\n\n      <div class=\"q-field\">\n        <label>Are your children currently in full-time education?</label>\n        <div class=\"btn-group\" data-field=\"educationStatus\">\n          <button class=\"btn-option\" data-value=\"fulltime\">Yes — full-time school</button>\n          <button class=\"btn-option\" data-value=\"preschool\">Preschool / nursery only</button>\n          <button class=\"btn-option\" data-value=\"mixed\">Some are, some aren't</button>\n          <button class=\"btn-option\" data-value=\"homeschool\">We homeschool already</button>\n          <button class=\"btn-option\" data-value=\"na\">Not applicable</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>How do you feel about worldschooling?</label>\n        <div class=\"btn-group\" data-field=\"worldschoolOpen\">\n          <button class=\"btn-option\" data-value=\"all-in\">All in — it's a big part of the appeal</button>\n          <button class=\"btn-option\" data-value=\"open\">Open — willing to try and learn</button>\n          <button class=\"btn-option\" data-value=\"unsure\">Unsure — I need to understand it more</button>\n          <button class=\"btn-option\" data-value=\"concerned\">Concerned — worried about gaps in learning</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\" id=\"schoolAlignmentField\" style=\"display:none\">\n        <label>Are you both fully on the same page about taking your child out of school?</label>\n        <div class=\"btn-group\" data-field=\"schoolAlignment\">\n          <button class=\"btn-option\" data-value=\"yes\">Yes — we're aligned</button>\n          <button class=\"btn-option\" data-value=\"no\">Not really — one of us is more hesitant</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 6: MINDSET -->\n    <div class=\"q-section\" id=\"section-6\">\n      <h2>Mindset &amp; Readiness</h2>\n      <p class=\"section-desc\">The bit that doesn't show up on a spreadsheet.</p>\n\n      <div class=\"q-field\">\n        <label>How comfortable are you with uncertainty and plans changing?</label>\n        <div class=\"slider-wrap\">\n          <div class=\"slider-readout\"><span id=\"uncReadout\">5</span><sub>/10</sub></div>\n          <input type=\"range\" min=\"1\" max=\"10\" value=\"5\" id=\"uncertaintySlider\" oninput=\"updateSlider(this)\">\n          <div class=\"slider-labels\">\n            <span>Low — I need a plan</span>\n            <span>High — I roll with it</span>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>How important is daily routine to your family?</label>\n        <div class=\"btn-group\" data-field=\"routine\">\n          <button class=\"btn-option\" data-value=\"low\">Low — we're flexible</button>\n          <button class=\"btn-option\" data-value=\"medium\">Medium — some structure helps</button>\n          <button class=\"btn-option\" data-value=\"high\">High — routine is essential</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Has your whole family bought into this idea?</label>\n        <div class=\"btn-group\" data-field=\"familyBuyIn\">\n          <button class=\"btn-option\" data-value=\"all-in\">Everyone is genuinely excited</button>\n          <button class=\"btn-option\" data-value=\"mostly\">Mostly — one or two need convincing</button>\n          <button class=\"btn-option\" data-value=\"split\">Split — real differences of opinion</button>\n          <button class=\"btn-option\" data-value=\"just-me\">Just me — selling it to the others</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>What worries you most about making this happen? (pick up to 2)</label>\n        <div class=\"btn-group\" data-field=\"biggestFear\" data-multi=\"2\">\n          <button class=\"btn-option\" data-value=\"money\">Money — running out</button>\n          <button class=\"btn-option\" data-value=\"work\">Work or career — getting back into it</button>\n          <button class=\"btn-option\" data-value=\"kids\">Kids — education, socialising, missing out</button>\n          <button class=\"btn-option\" data-value=\"safety\">Safety — health, accidents, the unknown</button>\n          <button class=\"btn-option\" data-value=\"returning\">Returning — what life looks like after</button>\n          <button class=\"btn-option\" data-value=\"none\">Honestly? Not much. We're ready.</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- SECTION 7: TRAVEL STYLE -->\n    <div class=\"q-section\" id=\"section-7\">\n      <h2>Travel Style</h2>\n      <p class=\"section-desc\">How you'd want to actually move and live.</p>\n\n      <div class=\"q-field\">\n        <label>What travel pace suits your family best?</label>\n        <div class=\"btn-group\" data-field=\"pace\">\n          <button class=\"btn-option\" data-value=\"slow\">Slow — 4–8 weeks per place</button>\n          <button class=\"btn-option\" data-value=\"medium\">Medium — 2–4 weeks per place</button>\n          <button class=\"btn-option\" data-value=\"fast\">Fast — as much as possible</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>What kind of environment do you thrive in?</label>\n        <div class=\"btn-group\" data-field=\"environment\">\n          <button class=\"btn-option\" data-value=\"city\">Cities — culture, food, buzz</button>\n          <button class=\"btn-option\" data-value=\"beach\">Beach / coast — sea, sun, slow</button>\n          <button class=\"btn-option\" data-value=\"nature\">Nature — mountains, forests, wild</button>\n          <button class=\"btn-option\" data-value=\"mix\">Mix of all — variety</button>\n        </div>\n      </div>\n\n      <div class=\"q-field\">\n        <label>Any regions already on your radar? (optional)</label>\n        <textarea id=\"destinationsInput\" placeholder=\"e.g. Southeast Asia, Portugal, New Zealand…\"></textarea>\n      </div>\n    </div>\n\n    <!-- NAV -->\n    <div class=\"q-nav\">\n      <button class=\"btn-back\" id=\"backBtn\" onclick=\"prevSection()\" style=\"visibility:hidden\">Back</button>\n      <button class=\"btn-next\" id=\"nextBtn\" onclick=\"nextSection()\">Continue</button>\n    </div>\n  </div>\n</div>\n\n<!-- ═══ RESULTS ═══ -->\n<div id=\"results\" class=\"screen\">\n  <div class=\"shell\">\n    <div class=\"result-card score-hero\" id=\"scoreHero\"></div>\n    <div class=\"profile-card\" id=\"profileCard\"></div>\n    <div class=\"swot-grid\">\n      <div class=\"swot-card strengths\">\n        <h4>What's working for you</h4>\n        <ul id=\"strengthsList\"></ul>\n      </div>\n      <div class=\"swot-card challenges\">\n        <h4>Areas to work on</h4>\n        <ul id=\"challengesList\"></ul>\n      </div>\n    </div>\n    <div class=\"actions-card\">\n      <h3>Concrete next actions</h3>\n      <ul id=\"actionsList\"></ul>\n    </div>\n    <div class=\"next-step\" id=\"nextStepCard\"></div>\n    <div class=\"cta-card\">\n      <div class=\"eyebrow\">Want to talk it through?</div>\n      <h3>Book a 1:1 with us</h3>\n      <p>We've done this. We travel full-time as a family and we know what it actually takes — not the highlight reel version, the real one. If you want to talk through your specific situation, work out where the gaps are, and make a plan that fits your family, we offer a personal 1:1 call.</p>\n      <a class=\"cta-btn\" href=\"/work-with-us\" target=\"_top\">Book your call →</a>\n    </div>\n    <button class=\"restart-link\" onclick=\"restart()\">Start the quiz again</button>\n  </div>\n</div>\n\n<script>\n  // ───── STATE ─────\n  const answers = {\n    adults: null,\n    hasChildren: null,\n    numChildren: null,\n    childExactAge: null,\n    childAges: null,\n    experience: null,\n    duration: null,\n    goal: null,\n    timeline: null,\n    workNow: null,\n    workLocation: null,\n    workWhenLeave: null,\n    newIncomeProgress: null,\n    travelIncome: null,\n    residualIncome: null,\n    savingsRate: null,\n    savingsDuration: null,\n    existingSavings: null,\n    homeExpenses: null,\n    spendingHabits: null,\n    educationStatus: null,\n    worldschoolOpen: null,\n    schoolAlignment: null,\n    uncertainty: 5,\n    routine: null,\n    familyBuyIn: null,\n    biggestFear: [],\n    pace: null,\n    environment: null,\n    destinations: '',\n  };\n\n  let currentSection = 1;\n  const TOTAL_SECTIONS = 7;\n\n  // ───── SCREEN SWITCHING ─────\n  function showScreen(id) {\n    document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));\n    document.getElementById(id).classList.add('active');\n    window.scrollTo(0, 0);\n  }\n\n  function startQuiz() {\n    showScreen('quiz');\n  }\n\n  // ───── BUTTON GROUP WIRING ─────\n  document.querySelectorAll('.btn-group').forEach(group => {\n    const field = group.dataset.field;\n    const multiAttr = group.dataset.multi;\n\n    if (multiAttr) {\n      const max = parseInt(multiAttr, 10);\n      group.querySelectorAll('.btn-option').forEach(btn => {\n        btn.addEventListener('click', () => {\n          const value = btn.dataset.value;\n          let arr = Array.isArray(answers[field]) ? [...answers[field]] : [];\n\n          if (value === 'none') {\n            // \"None\" is exclusive: select alone, or deselect.\n            arr = arr.includes('none') ? [] : ['none'];\n          } else {\n            // Any other choice deselects \"none\" first.\n            arr = arr.filter(v => v !== 'none');\n            if (arr.includes(value)) {\n              arr = arr.filter(v => v !== value);\n            } else if (arr.length < max) {\n              arr.push(value);\n            }\n          }\n          answers[field] = arr;\n          group.querySelectorAll('.btn-option').forEach(b => {\n            b.classList.toggle('selected', arr.includes(b.dataset.value));\n          });\n        });\n      });\n    } else {\n      group.querySelectorAll('.btn-option').forEach(btn => {\n        btn.addEventListener('click', () => {\n          group.querySelectorAll('.btn-option').forEach(b => b.classList.remove('selected'));\n          btn.classList.add('selected');\n          answers[field] = btn.dataset.value;\n          handleConditional(field);\n        });\n      });\n    }\n  });\n\n  // ───── CONDITIONAL DISPLAY ─────\n  function handleConditional(field) {\n    if (field === 'hasChildren') {\n      const show = answers.hasChildren === 'yes';\n      document.getElementById('numChildrenField').style.display = show ? 'block' : 'none';\n      if (!show) {\n        answers.numChildren = null;\n        answers.childAges = null;\n        answers.childExactAge = null;\n        document.getElementById('childAgeExactField').style.display = 'none';\n        document.getElementById('childAgesRangeField').style.display = 'none';\n        // Clear UI selections for the now-hidden fields.\n        document.querySelectorAll('#numChildrenField .btn-option, #childAgeExactField .btn-option, #childAgesRangeField .btn-option')\n          .forEach(b => b.classList.remove('selected'));\n      }\n      handleSchoolAlignment();\n    }\n\n    if (field === 'numChildren') {\n      const isOne = answers.numChildren === '1';\n      document.getElementById('childAgeExactField').style.display = isOne ? 'block' : 'none';\n      document.getElementById('childAgesRangeField').style.display = (answers.numChildren && !isOne) ? 'block' : 'none';\n      if (isOne) {\n        answers.childAges = null;\n        document.querySelectorAll('#childAgesRangeField .btn-option').forEach(b => b.classList.remove('selected'));\n      } else {\n        answers.childExactAge = null;\n        document.querySelectorAll('#childAgeExactField .btn-option').forEach(b => b.classList.remove('selected'));\n      }\n    }\n\n    if (field === 'childExactAge') {\n      const age = parseInt(answers.childExactAge, 10);\n      if (age <= 4) answers.childAges = 'all-young';\n      else if (age <= 11) answers.childAges = 'mixed';\n      else answers.childAges = 'all-older';\n    }\n\n    if (field === 'adults') {\n      handleSchoolAlignment();\n    }\n\n    if (field === 'workNow') {\n      const showLoc = answers.workNow === 'home-uk' || answers.workNow === 'self-employed';\n      const showWhen = answers.workNow !== 'not-working' && answers.workNow !== null;\n      document.getElementById('workLocationField').style.display = showLoc ? 'block' : 'none';\n      document.getElementById('workWhenLeaveField').style.display = showWhen ? 'block' : 'none';\n      document.getElementById('newIncomeProgressField').style.display = 'none';\n      if (!showLoc) {\n        answers.workLocation = null;\n        document.querySelectorAll('#workLocationField .btn-option').forEach(b => b.classList.remove('selected'));\n      }\n      if (!showWhen) {\n        answers.workWhenLeave = null;\n        answers.newIncomeProgress = null;\n        document.querySelectorAll('#workWhenLeaveField .btn-option, #newIncomeProgressField .btn-option').forEach(b => b.classList.remove('selected'));\n      }\n    }\n\n    if (field === 'workWhenLeave') {\n      const showNI = answers.workWhenLeave === 'new-income';\n      document.getElementById('newIncomeProgressField').style.display = showNI ? 'block' : 'none';\n      if (!showNI) {\n        answers.newIncomeProgress = null;\n        document.querySelectorAll('#newIncomeProgressField .btn-option').forEach(b => b.classList.remove('selected'));\n      }\n    }\n  }\n\n  function handleSchoolAlignment() {\n    const show = answers.adults === '2' && answers.hasChildren === 'yes';\n    document.getElementById('schoolAlignmentField').style.display = show ? 'block' : 'none';\n    if (!show) {\n      answers.schoolAlignment = null;\n      document.querySelectorAll('#schoolAlignmentField .btn-option').forEach(b => b.classList.remove('selected'));\n    }\n  }\n\n  function updateSlider(el) {\n    answers.uncertainty = parseInt(el.value, 10);\n    document.getElementById('uncReadout').textContent = el.value;\n  }\n\n  // ───── NAVIGATION ─────\n  function updateProgress() {\n    const pct = Math.round((currentSection / TOTAL_SECTIONS) * 100);\n    document.getElementById('progressFill').style.width = pct + '%';\n    document.getElementById('progressLabel').textContent = `Section ${currentSection} of ${TOTAL_SECTIONS}`;\n    document.getElementById('backBtn').style.visibility = currentSection === 1 ? 'hidden' : 'visible';\n    document.getElementById('nextBtn').textContent = currentSection === TOTAL_SECTIONS ? 'See My Results →' : 'Continue';\n  }\n\n  function showSection(n) {\n    document.querySelectorAll('.q-section').forEach(s => s.classList.remove('active'));\n    document.getElementById('section-' + n).classList.add('active');\n    currentSection = n;\n    updateProgress();\n    window.scrollTo({ top: 0 });\n  }\n\n  function nextSection() {\n    if (currentSection < TOTAL_SECTIONS) {\n      showSection(currentSection + 1);\n    } else {\n      answers.destinations = document.getElementById('destinationsInput').value.trim();\n      calculateAndShow();\n    }\n  }\n\n  function prevSection() {\n    if (currentSection > 1) showSection(currentSection - 1);\n  }\n\n  // ───── SCORING ─────\n  function calculateScore() {\n    let score = 30;\n\n    const workPts = { 'keep-going': 20, 'reduce': 10, 'new-income': 5, 'sabbatical': 3, 'unsure': -5, 'quit': -10 };\n    score += workPts[answers.workWhenLeave] || 0;\n\n    if (answers.workNow === 'anywhere') score += 5;\n    if (answers.workNow === 'home-uk' && answers.workLocation === 'no') score -= 5;\n    if (answers.workWhenLeave === 'new-income') {\n      const ipPts = { earning: 10, started: 3, idea: -3 };\n      score += ipPts[answers.newIncomeProgress] || 0;\n    }\n\n    score += (answers.uncertainty || 5) * 2;\n\n    const routinePts = { low: 10, medium: 0, high: -15 };\n    score += routinePts[answers.routine] || 0;\n\n    const expPts = { yes: 15, some: 5, no: -5 };\n    score += expPts[answers.experience] || 0;\n\n    const pacePts = { slow: 15, medium: 5, fast: -5 };\n    score += pacePts[answers.pace] || 0;\n\n    if (answers.duration === '1-3m' || answers.duration === '3-6m') score += 5;\n    if (answers.duration === '12m+') score -= 5;\n\n    if (answers.goal === 'test') score += 10;\n    else if (answers.goal) score += 5;\n\n    if (answers.adults === '1') score -= 5;\n\n    const cAgePts = { 'all-young': -10, mixed: -5, 'all-older': 0 };\n    score += cAgePts[answers.childAges] || 0;\n\n    const tiPts = { 'yes-both': 15, 'yes-one': 8, building: 0, no: -10 };\n    score += tiPts[answers.travelIncome] || 0;\n\n    const riPts = { 'yes-covers': 15, 'yes-partial': 7, potential: 3, no: 0 };\n    score += riPts[answers.residualIncome] || 0;\n\n    const srPts = { under50: -10, '50-250': 0, '251-500': 5, '501-1000': 10, '1000+': 15 };\n    score += srPts[answers.savingsRate] || 0;\n\n    const sdPts = { under6m: -5, '6-12m': 0, '1-2yr': 5, '2yr+': 10 };\n    score += sdPts[answers.savingsDuration] || 0;\n\n    const esPts = { 'yes-strong': 10, 'yes-some': 4, no: 0 };\n    score += esPts[answers.existingSavings] || 0;\n\n    const wsPts = { 'all-in': 8, open: 5, unsure: 0, concerned: -3 };\n    score += wsPts[answers.worldschoolOpen] || 0;\n\n    const fbPts = { 'all-in': 8, mostly: 4, split: -3, 'just-me': -6 };\n    score += fbPts[answers.familyBuyIn] || 0;\n\n    if (answers.homeExpenses === 'yes') score -= 5;\n    if (answers.schoolAlignment === 'yes') score += 5;\n\n    if (answers.routine === 'high' && answers.pace === 'fast') score -= 10;\n\n    return Math.max(0, Math.min(100, Math.round(score)));\n  }\n\n  function financiallyReady() {\n    return ['501-1000', '1000+'].includes(answers.savingsRate)\n      || answers.existingSavings === 'yes-strong'\n      || ['yes-both', 'yes-one'].includes(answers.travelIncome);\n  }\n\n  // ───── OUTPUT BUILDERS ─────\n  function getStyle(pace, env) {\n    const map = {\n      'slow-city': 'Slow Urban Immersion',\n      'slow-beach': 'Coastal Slow Travel',\n      'slow-nature': 'Nature Immersion',\n      'slow-mix': 'Balanced Slow Nomadic',\n      'medium-city': 'City Hopper',\n      'medium-beach': 'Beach & Culture',\n      'medium-nature': 'Active Explorer',\n      'medium-mix': 'Classic Family Nomad',\n      'fast-city': 'Urban Sprint',\n      'fast-beach': 'Island Hopper',\n      'fast-nature': 'Adventure Seeker',\n      'fast-mix': 'Everything Traveller',\n    };\n    return map[pace + '-' + env] || 'Family Traveller';\n  }\n\n  function getPaceText(pace) {\n    return ({ slow: '4–8 weeks per place', medium: '2–4 weeks per place', fast: 'Keep moving' })[pace] || '—';\n  }\n\n  function getRegions(pace, env) {\n    const map = {\n      'slow-city':   ['Chiang Mai', 'Medellín', 'Lisbon', 'Tbilisi', 'Tallinn'],\n      'slow-beach':  ['Bali', 'Costa Rica', 'Zanzibar', 'Koh Lanta', 'Algarve'],\n      'slow-nature': ['New Zealand', 'Patagonia', 'Costa Rica', 'Slovenia', 'Azores'],\n      'slow-mix':    ['Portugal', 'Mexico', 'Thailand', 'Colombia', 'Georgia'],\n      'medium-city':   ['Southeast Asia', 'Eastern Europe', 'Morocco', 'South America'],\n      'medium-beach':  ['Greek Islands', 'Caribbean', 'Southeast Asia coast', 'Canary Islands'],\n      'medium-nature': ['Central America', 'Balkans', 'South Africa', 'Nepal'],\n      'medium-mix':    ['Spain & Portugal', 'Thailand', 'Morocco', 'Vietnam'],\n      'fast-city':   ['Europe', 'Japan', 'South America cities'],\n      'fast-beach':  ['Philippines', 'Indonesia', 'Caribbean islands'],\n      'fast-nature': ['East Africa', 'South America', 'Australia & NZ'],\n      'fast-mix':    ['Southeast Asia', 'Central America', 'Southern Europe'],\n    };\n    return map[pace + '-' + env] || ['Southeast Asia', 'Southern Europe', 'Central America'];\n  }\n\n  function getRisks() {\n    const r = [];\n    if (answers.workWhenLeave === 'quit' || answers.workWhenLeave === 'unsure') r.push('Income gap on departure');\n    if (answers.workWhenLeave === 'new-income' && answers.newIncomeProgress === 'idea') r.push('Income plan not yet started');\n    if (answers.routine === 'high') r.push('High routine need');\n    if (answers.uncertainty < 4) r.push('Low uncertainty tolerance');\n    if (answers.pace === 'fast' && answers.childAges === 'all-young') r.push('Fast pace + young children');\n    if (answers.adults === '1') r.push('Solo parent');\n    if (answers.familyBuyIn === 'split' || answers.familyBuyIn === 'just-me') r.push('Family alignment');\n    if (answers.savingsRate === 'under50' && answers.travelIncome === 'no') r.push('Insufficient financial runway');\n    return r.slice(0, 3);\n  }\n\n  function getFamilyDesc() {\n    const adultText = answers.adults === '1' ? 'Solo parent' : answers.adults === '2' ? '2 adults' : answers.adults === '3+' ? '3+ adults' : 'Family';\n    if (answers.hasChildren !== 'yes') return adultText + ', no children';\n    const n = answers.numChildren || '?';\n    const ageMap = { 'all-young': 'all under 5', 'mixed': 'mixed ages', 'all-older': 'all 5+' };\n    const ageText = ageMap[answers.childAges] || '';\n    const kidsWord = n === '1' ? 'child' : 'children';\n    return `${adultText} · ${n} ${kidsWord}${ageText ? ` (${ageText})` : ''}`;\n  }\n\n  function getStrengths() {\n    const s = [];\n    if (answers.workNow === 'anywhere') s.push(\"Your job is already truly location-independent — you can keep earning exactly as you do now, from anywhere in the world\");\n    if (answers.workNow === 'home-uk' && answers.workLocation === 'yes') s.push(\"Your job can be done from abroad — you may be closer to location-independent than you realised\");\n    if (answers.workWhenLeave === 'keep-going') s.push(\"Your income travels with you — this removes the single biggest financial barrier for most families\");\n    if (answers.workWhenLeave === 'reduce') s.push(\"Part-time or reduced hours keeps money coming in and maintains an employment relationship to return to\");\n    if (answers.workWhenLeave === 'sabbatical') s.push(\"A sabbatical keeps your job secure — you can travel knowing there's something to come back to\");\n    if (answers.newIncomeProgress === 'earning') s.push(\"You're already earning from your new income source — that's a significant milestone most families haven't reached\");\n    if (answers.experience === 'yes') s.push(\"Previous long-term travel experience means you know what to expect and how your family copes on the road\");\n    if (answers.experience === 'some') s.push(\"You've done trips before — you have a baseline to build from\");\n    if (answers.uncertainty >= 7) s.push(\"High comfort with uncertainty makes you well-suited to the unpredictable nature of travel\");\n    if (answers.routine === 'low') s.push(\"A go-with-the-flow family adapts quickly on the road\");\n    if (answers.pace === 'slow') s.push(\"Slow travel is significantly cheaper, kinder on kids, and easier to sustain long-term\");\n    if (answers.goal === 'test') s.push(\"Testing the water first is the smartest approach — removes the pressure of an all-or-nothing commitment\");\n    if (answers.travelIncome === 'yes-both') s.push(\"Both adults earning while travelling is a very strong financial position\");\n    if (answers.travelIncome === 'yes-one') s.push(\"One income while travelling is enough for many families in affordable destinations\");\n    if (answers.residualIncome === 'yes-covers') s.push(\"Residual income covering your home costs means your savings go directly to travel\");\n    if (answers.residualIncome === 'yes-partial') s.push(\"Residual income as a supplement takes real financial pressure off the road\");\n    if (answers.savingsRate === '501-1000' || answers.savingsRate === '1000+') s.push(\"A strong monthly savings rate means your travel fund builds fast\");\n    if (answers.existingSavings === 'yes-strong') s.push(\"An existing savings pot gives you a meaningful head start\");\n    if (answers.worldschoolOpen === 'all-in') s.push(\"Being genuinely excited about worldschooling turns education from a barrier into a reason to travel\");\n    if (answers.familyBuyIn === 'all-in') s.push(\"Whole-family alignment is one of the biggest predictors of success — you have it\");\n    if (answers.schoolAlignment === 'yes') s.push(\"You're both aligned on taking your child out of school — removing that friction makes the decision a lot cleaner\");\n    return s;\n  }\n\n  function getChallenges() {\n    const c = [];\n    if (answers.workNow === 'home-uk' && answers.workLocation === 'no') c.push(\"Your current job is tied to your home country — working from home isn't the same as location-independence. Your plan for when you leave matters most\");\n    if (answers.workNow === 'office') c.push(\"Your current role requires physical presence, so the key question is what changes when you leave — sabbatical, resign, or a new income source\");\n    if (answers.workWhenLeave === 'quit') c.push(\"Resigning means no income from day one — your savings runway and/or a new income source needs to be firmly in place before you leave\");\n    if (answers.workWhenLeave === 'new-income' && answers.newIncomeProgress === 'idea') c.push(\"Having the idea for a new income source is very different from having the income — this needs real momentum before departure\");\n    if (answers.workWhenLeave === 'new-income' && answers.newIncomeProgress === 'started') c.push(\"You've started building new income but aren't earning yet — give this priority alongside your travel planning\");\n    if (answers.workWhenLeave === 'unsure') c.push(\"Not having a plan for work when you leave is the biggest gap in your readiness — this needs to be resolved before much else falls into place\");\n    if (answers.travelIncome === 'no') c.push(\"Living off savings alone works, but needs a very clear budget and a realistic timeline you can stick to\");\n    if (answers.travelIncome === 'building') c.push(\"Building travel income takes time — the further along you are before leaving, the less pressure on your savings\");\n    if (answers.residualIncome === 'no') c.push(\"No residual income means travel costs need to be fully covered by savings or earned income on the road\");\n    if (answers.savingsRate === 'under50') c.push(\"Very limited current savings capacity — even a focused spending audit could unlock more than you expect\");\n    if (answers.savingsRate === '50-250') c.push(\"Modest savings rate — look at subscriptions, eating out, and recurring costs. Small cuts compound quickly\");\n    if (answers.existingSavings === 'no') c.push(\"Starting savings from zero means you need lead time — be realistic about when you can leave based on when your pot is ready\");\n    if (answers.routine === 'high') c.push(\"High need for routine can make travel feel chaotic — slow travel and deliberate planning helps significantly\");\n    if (answers.uncertainty < 4) c.push(\"Low comfort with uncertainty is worth building gradually — the road will throw surprises regardless of how well you plan\");\n    if (answers.familyBuyIn === 'split') c.push(\"One of you being more keen than the rest is worth resolving before committing — travel works best as a fully shared decision\");\n    if (answers.familyBuyIn === 'just-me') c.push(\"Family alignment is crucial — real stories from families like yours tend to move people more than logistics spreadsheets\");\n    if (answers.childAges === 'all-young') c.push(\"Very young children add complexity — naps, kit, less flexibility. Totally doable, but needs more planning and a slower pace\");\n    if (answers.pace === 'fast' && answers.hasChildren === 'yes') c.push(\"Moving fast with kids is exhausting — even a small shift toward slower travel makes a big practical difference\");\n    if (answers.worldschoolOpen === 'concerned') c.push(\"Concerns about education gaps are valid and very common — most families find their children thrive with the right resources and approach\");\n    if (answers.duration === '12m+') c.push(\"12+ months requires a more robust financial plan — make sure income or savings genuinely cover the full stretch before committing\");\n    if (answers.homeExpenses === 'yes') c.push(\"Ongoing costs at home while you travel reduce your runway — factor these into your monthly budget calculation\");\n    if (answers.schoolAlignment === 'no') c.push(\"Not being fully aligned on taking your child out of school is worth resolving before anything else — it affects the whole plan\");\n    if (answers.adults === '1') c.push(\"Solo parenting on the road is completely achievable, but requires extra planning around rest, your own support, and budget buffers\");\n    return c;\n  }\n\n  function getActions(score) {\n    const a = [];\n    const ready = financiallyReady();\n\n    if (!answers.workWhenLeave || answers.workWhenLeave === 'unsure') a.push(\"The most important thing to figure out first: what happens to your income when you leave? Sabbatical, resign, go remote, or build something new — pick a path and start working it\");\n    if (answers.workNow === 'home-uk' && (answers.workLocation === 'no' || answers.workLocation === 'maybe')) a.push(\"Check your employment contract and speak to HR — many people assume they can't work abroad when actually there's no explicit restriction. It's worth the conversation\");\n    if (answers.workWhenLeave === 'sabbatical' || answers.workWhenLeave === 'quit') a.push(\"Have a direct conversation with your employer about sabbatical or career break options — frame it professionally and you may be surprised by the flexibility on offer\");\n    if (answers.workWhenLeave === 'new-income' && (answers.newIncomeProgress === 'idea' || answers.newIncomeProgress === 'started')) a.push(\"Start treating your new income source as a second job right now — even £200–£500/month before you leave proves the model and significantly reduces the pressure\");\n    if (answers.spendingHabits === 'some-cuts' || answers.spendingHabits === 'lots-of-cuts') a.push(\"Do a 30-minute spending audit — go through your last two bank statements and highlight everything that isn't essential. Most families find £100–£300/month they can redirect without feeling it\");\n    if (answers.travelIncome === 'no' || answers.travelIncome === 'building') a.push(\"Work out your financial runway: estimate your monthly travel cost, then divide your savings by that number. That's how many months you can travel. Build the plan around that number\");\n    if (answers.residualIncome === 'potential') a.push(\"Get a rental valuation on your home — for many families, renting it out covers a large chunk of travel costs and changes the whole financial picture\");\n    if (answers.homeExpenses === 'yes') a.push(\"List every cost that will continue at home while you're away and total it up — this is your fixed monthly overhead on top of travel costs, and it needs to be part of your budget from day one\");\n    if (answers.worldschoolOpen === 'unsure' || answers.worldschoolOpen === 'concerned') a.push(\"Spend one hour exploring worldschooling: join a Facebook group, find one family blog, listen to one podcast episode. Real examples from real families are far more reassuring than theory\");\n    if (answers.schoolAlignment === 'no') a.push(\"Before anything else, get aligned on the school question as a couple — it underpins the whole plan. Read about how other families navigated it and talk through the specific concerns\");\n    if (answers.familyBuyIn === 'split' || answers.familyBuyIn === 'just-me') a.push(\"Share one story from a family in a similar situation who actually did it — a short video or blog post tends to shift doubters far more than spreadsheets or logistics conversations\");\n    if (answers.routine === 'high' || answers.uncertainty < 5) a.push(\"Build your tolerance for the unexpected gradually — a weekend away with no fixed plan, a spontaneous day out. The ability to adapt is a skill and it can be trained before you leave\");\n    if (ready && (answers.experience === 'no' || answers.experience === 'some')) a.push(\"Once your savings foundation is in place, plan a 2–3 week trip to somewhere you'd genuinely consider living — treat it as a research trip, not a holiday. You'll learn things about your family on the road that no amount of planning can tell you\");\n    if (score >= 70 && (answers.workWhenLeave === 'keep-going' || answers.travelIncome === 'yes-both' || answers.travelIncome === 'yes-one')) a.push(\"Set a departure window — even a rough quarter and year. A real date makes everything more concrete and gives the planning genuine momentum\");\n\n    return a;\n  }\n\n  function getNextStep(score) {\n    const ready = financiallyReady();\n    if (score >= 70) {\n      if (ready) {\n        return {\n          title: \"You're ready to take a serious next step\",\n          body: \"The foundations are there. The best thing you can do now is stop planning in the abstract and start doing something real — whether that's setting a departure date, telling people, or booking the first leg. Momentum matters more than a perfect plan at this stage.\",\n        };\n      }\n      return {\n        title: \"Sort the money, then move fast\",\n        body: \"Your mindset, family alignment, and work situation look solid — the missing piece is the financial foundation. Get that in order first: build the savings pot, confirm the income picture, and then move quickly. You won't need long once the money is sorted.\",\n      };\n    }\n    if (score >= 40) {\n      return {\n        title: \"Close the gaps, then commit to a date\",\n        body: \"You've got some real foundations here but a few things need resolving — most likely around income, savings, or alignment. The best approach is to identify your one or two biggest blockers, work on those deliberately over the next 6–12 months, and set a target departure window to work backwards from. Don't wait until everything is perfect — that moment doesn't come.\",\n      };\n    }\n    return {\n      title: \"Start with the foundations\",\n      body: \"The dream is real, the groundwork isn't there yet — and that's completely normal. Most families who travel long-term spent 1–3 years getting ready. Focus first on your two biggest blockers (usually income and savings), build consistency, and start surrounding yourself with families who've actually done it. The gap between where you are and where you want to be is smaller than it feels right now.\",\n    };\n  }\n\n  function getTagline(score) {\n    if (score >= 70) return \"You're closer than you think.\";\n    if (score >= 40) return \"You've got the foundations — now close the gaps.\";\n    return \"There's work to do, but the dream is real.\";\n  }\n\n  // ───── RENDER RESULTS ─────\n  function calculateAndShow() {\n    const score = calculateScore();\n    let band, cls;\n    if (score >= 70) { band = 'High Readiness'; cls = 'high'; }\n    else if (score >= 40) { band = 'Medium Readiness'; cls = 'medium'; }\n    else { band = 'Needs Preparation'; cls = 'low'; }\n\n    document.getElementById('scoreHero').innerHTML = `\n      <div class=\"score-band ${cls}\">${band}</div>\n      <div class=\"score-number ${cls}\">${score}<span class=\"score-out-of\">/100</span></div>\n      <div class=\"score-tagline\">${getTagline(score)}</div>\n    `;\n\n    const style = getStyle(answers.pace, answers.environment);\n    const regions = getRegions(answers.pace, answers.environment);\n    const risks = getRisks();\n\n    document.getElementById('profileCard').innerHTML = `\n      <h3>Your family profile</h3>\n      <div class=\"profile-row\">\n        <div class=\"profile-label\">Family</div>\n        <div class=\"profile-value\">${getFamilyDesc()}</div>\n      </div>\n      <div class=\"profile-row\">\n        <div class=\"profile-label\">Travel Style</div>\n        <div class=\"profile-value\">${style}</div>\n      </div>\n      <div class=\"profile-row\">\n        <div class=\"profile-label\">Ideal Pace</div>\n        <div class=\"profile-value\">${getPaceText(answers.pace)}</div>\n      </div>\n      <div class=\"profile-row\">\n        <div class=\"profile-label\">Good Fit Regions</div>\n        <div class=\"profile-value\">${regions.map(r => '<span class=\"tag\">' + r + '</span>').join('')}</div>\n      </div>\n      <div class=\"profile-row\">\n        <div class=\"profile-label\">Key Risk Factors</div>\n        <div class=\"profile-value\">${risks.length ? risks.join(' · ') : 'None identified'}</div>\n      </div>\n    `;\n\n    const strengths = getStrengths();\n    const challenges = getChallenges();\n    document.getElementById('strengthsList').innerHTML =\n      (strengths.length ? strengths : ['No specific strengths flagged from your answers.']).map(s => '<li>' + s + '</li>').join('');\n    document.getElementById('challengesList').innerHTML =\n      (challenges.length ? challenges : ['No significant challenges identified.']).map(c => '<li>' + c + '</li>').join('');\n\n    const actions = getActions(score);\n    document.getElementById('actionsList').innerHTML =\n      (actions.length ? actions : ['Take a 2-week trip together as a stress test before committing to anything longer.']).map(a => '<li>' + a + '</li>').join('');\n\n    const ns = getNextStep(score);\n    document.getElementById('nextStepCard').innerHTML = '<h3>' + ns.title + '</h3><p>' + ns.body + '</p>';\n\n    showScreen('results');\n  }\n\n  // ───── RESTART ─────\n  function restart() {\n    Object.keys(answers).forEach(k => {\n      if (k === 'biggestFear') answers[k] = [];\n      else if (k === 'uncertainty') answers[k] = 5;\n      else if (k === 'destinations') answers[k] = '';\n      else answers[k] = null;\n    });\n    document.querySelectorAll('.btn-option').forEach(b => b.classList.remove('selected'));\n    document.getElementById('uncertaintySlider').value = 5;\n    document.getElementById('uncReadout').textContent = '5';\n    document.getElementById('destinationsInput').value = '';\n    document.getElementById('numChildrenField').style.display = 'none';\n    document.getElementById('childAgeExactField').style.display = 'none';\n    document.getElementById('childAgesRangeField').style.display = 'none';\n    document.getElementById('workLocationField').style.display = 'none';\n    document.getElementById('workWhenLeaveField').style.display = 'none';\n    document.getElementById('newIncomeProgressField').style.display = 'none';\n    document.getElementById('schoolAlignmentField').style.display = 'none';\n    currentSection = 1;\n    showSection(1);\n    showScreen('quiz');\n  }\n\n  // ───── INIT ─────\n  updateProgress();\n</script>\n</body>\n</html>\n"
